import React from 'react';
import { BadgeIndicator as CarbonBadgeIndicator } from '@carbon/react';

const BadgeIndicator = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonBadgeIndicator
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonBadgeIndicator>
    );
};

BadgeIndicator.defaultProps = {
    className: ''
};

export default BadgeIndicator;
